module RefModule (
    input [7:0] x,
    input [7:0] z,
    output [7:0] sum
);

    // Perform addition
      wire _n01 = x[0] ^ z[0];
  wire _c01 = x[0] & z[0];
  wire _n02 = x[1] ^ z[1] ^ _c01;
  wire _c02 = (x[1] & z[1]) | (x[1] & _c01) | (z[1] & _c01);
  wire _n03 = x[2] ^ z[2] ^ _c02;
  wire _c03 = (x[2] & z[2]) | (x[2] & _c02) | (z[2] & _c02);
  wire _n04 = x[3] ^ z[3] ^ _c03;
  wire _c04 = (x[3] & z[3]) | (x[3] & _c03) | (z[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};

endmodule
